"use client";

import { useState, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { toast } from "sonner";

import { loginAction, type LoginState } from "@/actions/auth/login";
import { loginSchema, type LoginInput } from "@/lib/validations/auth";
import { ROUTES } from "@/lib/constants/routes";

/** Validate that a redirect target is a safe internal path. */
function getSafeRedirect(value: string | null): string {
  if (!value) return ROUTES.DASHBOARD;
  // Must start with "/" but not "//" or "/\" (protocol-relative or escaped)
  if (value.startsWith("/") && !value.startsWith("//") && !value.startsWith("/\\")) {
    return value;
  }
  return ROUTES.DASHBOARD;
}
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
} from "@/components/ui/card";

/* ============================================
   Login Page
   Arabic RTL login form.
   ============================================ */

export default function LoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const redirect = getSafeRedirect(searchParams.get("redirect"));

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginInput>({
    resolver: zodResolver(loginSchema),
    defaultValues: { email: "", password: "" },
  });

  const onSubmit = async (data: LoginInput) => {
    setIsSubmitting(true);

    try {
      const formData = new FormData();
      formData.append("email", data.email);
      formData.append("password", data.password);

      const result: LoginState = await loginAction(
        { success: false },
        formData
      );

      if (result.success) {
        toast.success("تم تسجيل الدخول بنجاح");
        router.push(redirect);
        router.refresh();
      } else {
        toast.error(result.error ?? "فشل تسجيل الدخول");
      }
    } catch {
      toast.error("حدث خطأ غير متوقع. يرجى المحاولة مرة أخرى.");
    } finally {
      setIsSubmitting(false);
    }
  };

  useEffect(() => {
    const reason = searchParams.get("reason");
    if (reason === "expired") {
      toast.info("انتهت صلاحية جلستك. يرجى تسجيل الدخول مرة أخرى.");
    }
  }, [searchParams]);

  return (
    <Card className="w-full max-w-sm">
      <CardHeader className="space-y-2 text-center">
        <CardTitle className="text-2xl">تسجيل الدخول</CardTitle>
        <CardDescription>
          أدخل بياناتك للوصول إلى لوحة التحكم
        </CardDescription>
      </CardHeader>
      <form onSubmit={handleSubmit(onSubmit)} noValidate>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="email">البريد الإلكتروني</Label>
            <Input
              id="email"
              type="email"
              autoComplete="email"
              placeholder="you@example.com"
              dir="ltr"
              className="text-right"
              {...register("email")}
            />
            {errors.email && (
              <p className="text-sm text-destructive">
                {errors.email.message}
              </p>
            )}
          </div>

          <div className="space-y-2">
            <Label htmlFor="password">كلمة المرور</Label>
            <Input
              id="password"
              type="password"
              autoComplete="current-password"
              placeholder="••••••••"
              dir="ltr"
              className="text-right"
              {...register("password")}
            />
            {errors.password && (
              <p className="text-sm text-destructive">
                {errors.password.message}
              </p>
            )}
          </div>
        </CardContent>

        <CardFooter>
          <Button
            type="submit"
            className="w-full"
            disabled={isSubmitting}
          >
            {isSubmitting ? (
              <span className="flex items-center gap-2">
                <span className="h-4 w-4 animate-spin rounded-full border-2 border-primary-foreground border-t-transparent" />
                جارٍ تسجيل الدخول...
              </span>
            ) : (
              "زر تسجيل الدخول"
            )}
          </Button>
        </CardFooter>
      </form>
    </Card>
  );
}

"use client";

import { useState, useCallback } from "react";
import {
  Calendar,
  Video,
  Download,
  Eye,
  Play,
  Clock,
  Loader2,
} from "lucide-react";

import { Button } from "@/components/ui/button";
import { ReviewPlayer } from "@/components/review/review-player";
import { formatDate } from "@/lib/utils/format";
import { formatBytes } from "@/lib/utils/format";
import { formatDuration, formatResolution } from "@/lib/video/metadata";
import { trackDownloadAction } from "@/actions/deliveries/track-download";
import { BRANDING } from "@/config/branding";
import type { PublicDeliveryData } from "@/types/delivery";

/* ============================================
   DeliveryPortal — Main client portal
   Premium video gallery with player + download.
   ============================================ */

type DeliveryPortalProps = {
  data: PublicDeliveryData;
  slug: string;
};

export function DeliveryPortal({ data, slug }: DeliveryPortalProps) {
  const [playerTarget, setPlayerTarget] = useState<{ url: string; title: string; videoId: string } | null>(null);
  const [downloading, setDownloading] = useState<string | null>(null);

  const handlePlay = useCallback((streamUrl: string, title: string, videoId: string) => {
    if (!data.allowStreaming || !streamUrl) return;
    setPlayerTarget({ url: streamUrl, title, videoId });
  }, [data.allowStreaming]);

  const handleDownload = useCallback(async (videoId: string, downloadUrl: string) => {
    if (!data.downloadEnabled || !downloadUrl) return;
    setDownloading(videoId);

    try {
      // Track download via server action (gets fresh signed URL)
      const result = await trackDownloadAction(
        // We don't have deliveryId here, pass empty — the action handles it
        // Actually, the portal already has signed URLs from accessDeliveryAction
        // Just redirect to the download URL
        "",
        videoId,
        ""
      );

      // If trackDownloadAction fails, use the pre-signed URL directly
      const url = result.success && result.url ? result.url : downloadUrl;
      window.location.href = url;
    } catch {
      // Fallback to pre-signed URL
      window.location.href = downloadUrl;
    } finally {
      setDownloading(null);
    }
  }, [data.downloadEnabled]);

  return (
    <main className="min-h-dvh bg-background">
      {/* Header */}
      <header className="border-b bg-card/50 backdrop-blur">
        <div className="mx-auto max-w-5xl px-4 py-6">
          <div className="flex items-center gap-3">
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={BRANDING.logo.full}
              alt={BRANDING.companyName}
              className="h-10 w-10 rounded-lg object-contain"
            />
            <div>
              <h1 className="text-lg font-bold tracking-tight">{data.title}</h1>
              <p className="text-xs text-muted-foreground">
                {data.project.name} · {data.project.projectCode}
              </p>
            </div>
          </div>

          {/* Meta info */}
          <div className="mt-4 flex flex-wrap items-center gap-4 text-xs text-muted-foreground">
            <span className="flex items-center gap-1.5">
              <Video className="h-3.5 w-3.5" />
              {data.videoCount} فيديو
            </span>
            <span className="flex items-center gap-1.5">
              <Eye className="h-3.5 w-3.5" />
              {data.viewCount} مشاهدة
            </span>
            <span className="flex items-center gap-1.5">
              <Download className="h-3.5 w-3.5" />
              {data.downloadCount} تحميل
            </span>
            {data.expiresAt && (
              <span className="flex items-center gap-1.5">
                <Calendar className="h-3.5 w-3.5" />
                ينتهي في {formatDate(data.expiresAt)}
              </span>
            )}
          </div>
        </div>
      </header>

      {/* Video Grid */}
      <section className="mx-auto max-w-5xl px-4 py-8">
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {data.videos.map((video) => (
            <div
              key={video.id}
              className="group overflow-hidden rounded-xl border bg-card transition-shadow hover:shadow-lg"
            >
              {/* Thumbnail */}
              <div
                className="relative aspect-video cursor-pointer bg-muted"
                onClick={() => handlePlay(video.streamUrl, video.title, video.videoId)}
                role={data.allowStreaming && video.streamUrl ? "button" : undefined}
                aria-label={`تشغيل ${video.title}`}
              >
                {video.thumbnailUrl ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img
                    src={video.thumbnailUrl}
                    alt={video.title}
                    className="h-full w-full object-cover transition-transform group-hover:scale-105"
                    loading="lazy"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center">
                    <Video className="h-10 w-10 text-muted-foreground/30" />
                  </div>
                )}

                {/* Play overlay */}
                {data.allowStreaming && video.streamUrl && (
                  <div className="absolute inset-0 flex items-center justify-center bg-black/0 transition-colors group-hover:bg-black/30">
                    <span className="flex h-12 w-12 items-center justify-center rounded-full bg-primary/90 opacity-0 transition-opacity group-hover:opacity-100">
                      <Play className="h-5 w-5 text-primary-foreground" />
                    </span>
                  </div>
                )}

                {/* Duration badge */}
                {video.duration && (
                  <span className="absolute bottom-2 end-2 rounded bg-black/70 px-1.5 py-0.5 text-xs font-medium text-white">
                    {formatDuration(video.duration)}
                  </span>
                )}
              </div>

              {/* Info */}
              <div className="space-y-2 p-3">
                <p className="truncate text-sm font-medium">{video.title}</p>
                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                  <span>{formatBytes(video.fileSize)}</span>
                  <span>·</span>
                  <span>{formatResolution(video.width, video.height)}</span>
                </div>

                {/* Download button */}
                {data.downloadEnabled && video.downloadUrl && (
                  <Button
                    variant="outline"
                    size="sm"
                    className="w-full"
                    onClick={() => handleDownload(video.videoId, video.downloadUrl)}
                    disabled={downloading === video.videoId}
                  >
                    {downloading === video.videoId ? (
                      <Loader2 className="h-3.5 w-3.5 animate-spin" />
                    ) : (
                      <Download className="h-3.5 w-3.5" />
                    )}
                    تحميل
                  </Button>
                )}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Footer */}
      <footer className="border-t py-4">
        <div className="mx-auto flex max-w-5xl items-center justify-center gap-2 px-4 text-xs text-muted-foreground/60">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={BRANDING.logo.full} alt={BRANDING.companyName} className="h-4 w-4 rounded object-contain" />
          {BRANDING.companyName} — {BRANDING.tagline}
        </div>
      </footer>

      {/* Video Review Player */}
      {playerTarget && (
        <ReviewPlayer
          src={playerTarget.url}
          title={playerTarget.title}
          onClose={() => setPlayerTarget(null)}
          autoPlay
          videoId={playerTarget.videoId}
          deliveryId={data.deliveryId}
        />
      )}
    </main>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";

import { accessDeliveryAction } from "@/actions/deliveries/access-delivery";
import { DeliveryPortal } from "@/components/delivery/delivery-portal";
import { PasswordScreen } from "@/components/delivery/password-screen";
import { ExpiredScreen } from "@/components/delivery/expired-screen";
import { DisabledScreen } from "@/components/delivery/disabled-screen";
import type { PublicDeliveryData } from "@/types/delivery";

/* ============================================
   DeliveryPortalAccess — Handles access flow
   1. Calls accessDeliveryAction on mount
   2. Shows password screen if needed
   3. Renders DeliveryPortal with signed URLs
   ============================================ */

type DeliveryPortalAccessProps = {
  slug: string;
};

export function DeliveryPortalAccess({ slug }: DeliveryPortalAccessProps) {
  const [data, setData] = useState<PublicDeliveryData | null>(null);
  const [status, setStatus] = useState<"loading" | "active" | "expired" | "disabled" | "password-required">("loading");
  const [error, setError] = useState("");
  const hasFetched = useRef(false);

  useEffect(() => {
    if (hasFetched.current) return;
    hasFetched.current = true;
    let active = true;
    (async () => {
      const result = await accessDeliveryAction(slug);
      if (!active) return;
      if (result.success && result.data) {
        setData(result.data);
        setStatus("active");
      } else {
        if (result.status === "expired") {
          setStatus("expired");
        } else if (result.status === "disabled") {
          setStatus("disabled");
        } else if (result.status === "password-required") {
          setStatus("password-required");
          setError(result.error ?? "كلمة المرور مطلوبة");
        } else {
          setStatus("disabled");
          setError(result.error ?? "غير متاح");
        }
      }
    })();
    return () => { active = false };
  }, [slug]);

  if (status === "loading") {
    return (
      <main className="flex min-h-dvh items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-muted border-t-primary" />
      </main>
    );
  }

  if (status === "expired") {
    return <ExpiredScreen />;
  }

  if (status === "disabled") {
    return <DisabledScreen />;
  }

  if (status === "password-required") {
    return (
      <PasswordScreen
        slug={slug}
        onSuccess={(d) => {
          setData(d);
          setStatus("active");
        }}
      />
    );
  }

  if (data) {
    return <DeliveryPortal data={data} slug={slug} />;
  }

  return <DisabledScreen />;
}

"use client";

import { useState, useCallback } from "react";
import { Loader2, Lock } from "lucide-react";

import { BRANDING } from "@/config/branding";
