import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { storageService } from "@/lib/storage/storage.service";

/* ============================================
   Health Check API Route
   /api/health
   Verifies: Database, Storage, Auth config.
   ============================================ */

export const maxDuration = 10;

export async function GET() {
  const checks = {
    database: false,
    storage: false,
    auth: false,
    timestamp: new Date().toISOString(),
  };

  const errors: string[] = [];

  // 1. Database check
  try {
    await prisma.$queryRaw`SELECT 1`;
    checks.database = true;
  } catch (err) {
    errors.push(`Database: ${err instanceof Error ? err.message : "connection failed"}`);
  }

  // 2. Storage check (just verify config exists, don't make network call)
  try {
    if (storageService.bucket) {
      checks.storage = true;
    } else {
      errors.push("Storage: no bucket configured");
    }
  } catch (err) {
    errors.push(`Storage: ${err instanceof Error ? err.message : "config error"}`);
  }

  // 3. Auth check (verify AUTH_SECRET is set)
  try {
    const secret = process.env.AUTH_SECRET;
    if (secret && secret.length > 0) {
      checks.auth = true;
    } else {
      errors.push("Auth: AUTH_SECRET not set");
    }
  } catch {
    errors.push("Auth: configuration error");
  }

  const isHealthy = checks.database && checks.storage && checks.auth;

  return NextResponse.json(
    {
      status: isHealthy ? "healthy" : "unhealthy",
      checks,
      errors: errors.length > 0 ? errors : undefined,
    },
    { status: isHealthy ? 200 : 503 }
  );
}

import { NextRequest, NextResponse } from "next/server";

import { getCurrentUser } from "@/lib/auth/session";
import { storageService } from "@/lib/storage/storage.service";
import { generateStorageKey, getMimeType, getExtension, validateVideoFile } from "@/lib/video/metadata";

export const maxDuration = 60;

/* ============================================
   Upload API Route
   Handles multipart video uploads via StorageService.
   Provider-agnostic — no direct Cloudflare imports.
   ============================================ */

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json(
      { error: "يجب تسجيل الدخول" },
      { status: 401 }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file") as File | null;
    const projectId = formData.get("projectId") as string | null;

    if (!file) {
      return NextResponse.json(
        { error: "الملف مطلوب" },
        { status: 400 }
      );
    }

    if (!projectId) {
      return NextResponse.json(
        { error: "المشروع مطلوب" },
        { status: 400 }
      );
    }

    // Validate file type and size
    const validation = validateVideoFile(file);
    if (!validation.valid) {
      return NextResponse.json(
        { error: validation.error },
        { status: 400 }
      );
    }

    // Generate storage key
    const storageKey = generateStorageKey(projectId, file.name);
    const mimeType = getMimeType(file);
    const extension = getExtension(file.name);

    // Read file as buffer
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // Upload via StorageService
    await storageService.upload({
      key: storageKey,
      body: buffer,
      contentType: mimeType,
      metadata: {
        "original-filename": file.name,
        "project-id": projectId,
      },
    });

    return NextResponse.json({
      success: true,
      storageKey,
      storageBucket: storageService.bucket,
      mimeType,
      extension,
      fileSize: file.size,
    });
  } catch (error) {
    console.error("Upload error:", error);
    return NextResponse.json(
      { error: "فشل في رفع الملف" },
      { status: 500 }
    );
  }
}

